<?php $pageTitle = 'Alimentação • Movimentações'; $mealTypes = rt2027_food_meal_types(); ?>
<div class="rt-admin-shell"><?php include __DIR__ . '/../partials/admin_sidebar.php'; ?><main class="rt-admin-content p-4 lg:p-8"><div class="rt-admin-topbar rounded-3xl"><div><div class="rt-admin-title">Movimentações de estoque</div><div class="rt-admin-subtitle">Histórico visual de entradas, saídas automáticas e reversões manuais do estoque da alimentação.</div></div></div>
